import React, { useState, useEffect, useCallback, useRef } from "react";

// ─── Global CSS ───────────────────────────────────────────────────────────────
// ── Полифил window.storage для запуска вне Claude.ai ─────────────────────────
if (!window.storage) {
  window.storage = {
    get: async (key) => {
      const value = localStorage.getItem(key);
      if (value === null) throw new Error('Key not found: ' + key);
      return { key, value };
    },
    set: async (key, value) => {
      localStorage.setItem(key, value);
      return { key, value };
    },
    delete: async (key) => {
      localStorage.removeItem(key);
      return { key, deleted: true };
    },
    list: async (prefix) => {
      const keys = [];
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        if (!prefix || k.startsWith(prefix)) keys.push(k);
      }
      return { keys };
    },
  };
}

const GLOBAL_CSS = `
  @font-face{font-family:'Dwarven Stonecraft';src:url('data:font/otf;base64,') format('opentype');font-weight:normal;font-style:normal}
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --ink:#0d0a06;--parchment:#f2dea8;--parchment-dark:#c8a84e;
    --gold:#b8860b;--gold-bright:#d4a017;--gold-dim:#6b5510;
    --crimson:#8b1a1a;--blood:#5a0e0e;--stone:#1a1410;
    --stone-mid:#251e16;--stone-light:#332a1e;--stone-border:#4a3c28;
    --font-display:'Dwarven Stonecraft',serif;
    --font-title:'Cinzel',serif;--font-body:'Lora',serif;
  }
  body{background:var(--ink);color:var(--parchment);font-family:var(--font-body);font-size:clamp(20px,2.2vw,36px);line-height:1.65;letter-spacing:0.02em;min-height:100vh}
  ::-webkit-scrollbar{width:6px;background:var(--ink)}
  ::-webkit-scrollbar-thumb{background:var(--gold-dim);border-radius:3px}
  input,select,textarea{font-family:var(--font-body);background:var(--stone);color:var(--parchment);border:1px solid var(--stone-border);border-radius:4px;padding:10px 14px;font-size:28px;outline:none;transition:border-color .2s,box-shadow .2s;width:100%}
  input:focus,select:focus,textarea:focus{border-color:var(--gold);box-shadow:0 0 8px rgba(201,168,76,0.25)}
  select option{background:var(--stone);color:var(--parchment)}
  button{font-family:var(--font-title);cursor:pointer;border:none;letter-spacing:0.1em;transition:all .2s}
  input[type=number]::-webkit-inner-spin-button{opacity:.4}
  @keyframes flicker{0%,100%{opacity:1}50%{opacity:.85}70%{opacity:.95}}
  @keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
  @keyframes savedPop{0%{opacity:0;transform:scale(.8)}20%{opacity:1;transform:scale(1.05)}30%{transform:scale(1)}80%{opacity:1}100%{opacity:0}}
  @keyframes diceRoll{0%{transform:rotate(0deg) scale(1)}50%{transform:rotate(180deg) scale(1.3)}100%{transform:rotate(360deg) scale(1)}}
  @keyframes expandIn{from{opacity:0;transform:translateY(-6px)}to{opacity:1;transform:translateY(0)}}
  @keyframes spin{to{transform:rotate(360deg)}}
  .anim-fadeup{animation:fadeUp .5s ease both}
  .anim-saved{animation:savedPop 2s ease both}
  .dice-spin{animation:diceRoll .6s ease both}
  .expand-in{animation:expandIn .25s ease both}
  .detail-body{overflow:hidden;transition:max-height .35s cubic-bezier(0.4,0,0.2,1),opacity .25s ease}

  /* ── Адаптив ─────────────────────────────────────── */
  @media(max-width:640px){
    body{font-size:20px}
    input,select,textarea{font-size:17px;padding:8px 11px}
    .resp-pad{padding:12px!important}
    .resp-hide{display:none!important}
    .resp-col1{grid-template-columns:1fr!important}
    .resp-col1f{flex-direction:column!important}
    .resp-nowrap{flex-wrap:nowrap!important;overflow-x:auto}
    .resp-fs-sm{font-size:11px!important}
    .resp-step-label{display:none!important}
  }
  @media(max-width:900px){
    .resp-pad-md{padding:16px 14px!important}
    .resp-col1-md{grid-template-columns:1fr!important}
    .resp-col2-md{grid-template-columns:1fr 1fr!important}
  }
`;

const FontLoader = () => {
  useEffect(() => {
    const l = document.createElement("link");
    l.href = "https://fonts.googleapis.com/css2?family=Cinzel:wght@400;600;700&family=Lora:ital,wght@0,400;0,500;0,600;1,400&family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap";
    l.rel = "stylesheet"; document.head.appendChild(l);
    const s = document.createElement("style"); s.textContent = GLOBAL_CSS; document.head.appendChild(s);
    return () => { try{document.head.removeChild(l);document.head.removeChild(s);}catch(e){} };
  }, []);
  return null;
};

