// ═══════════════════════════════════════════════════════════════════════════════
// ─── UI КОМПОНЕНТЫ ─────────────────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════════

const Panel = ({ children, style }) => (
  <div style={{background:"linear-gradient(145deg,var(--stone-mid),var(--stone))",border:"1px solid var(--stone-border)",borderRadius:8,padding:18,position:"relative",...style}}>
    {children}
  </div>
);

const Btn = ({ children, onClick, variant="primary", size="md", style, disabled }) => {
  const sz={sm:{padding:"4px 12px",fontSize:12},md:{padding:"8px 18px",fontSize:13},lg:{padding:"12px 26px",fontSize:14}}[size];
  const va={
    primary:{background:"linear-gradient(135deg,#7a5a10,#c9a84c)",color:"#0d0a06",boxShadow:"0 2px 8px rgba(201,168,76,0.25)"},
    secondary:{background:"transparent",border:"1px solid var(--stone-border)",color:"var(--parchment)"},
    danger:{background:"linear-gradient(135deg,var(--blood),var(--crimson))",color:"var(--parchment)"},
    ghost:{background:"rgba(201,168,76,0.07)",color:"var(--gold)",border:"1px solid rgba(201,168,76,0.2)"},
  }[variant];
  return (
    <button onClick={onClick} disabled={disabled}
      style={{...sz,...va,borderRadius:4,cursor:disabled?"not-allowed":"pointer",opacity:disabled?.5:1,display:"inline-flex",alignItems:"center",justifyContent:"center",gap:6,letterSpacing:"0.06em",transition:"all .2s",...style}}
      onMouseEnter={e=>{if(!disabled){e.currentTarget.style.filter="brightness(1.2)";e.currentTarget.style.transform="translateY(-1px)";}}}
      onMouseLeave={e=>{e.currentTarget.style.filter="";e.currentTarget.style.transform="";}}>
      {children}
    </button>
  );
};

const OrnLine = ({color="var(--gold-dim)"}) => (
  <svg width="100%" height="14" viewBox="0 0 300 14" preserveAspectRatio="none" style={{display:"block",marginBottom:10}}>
    <line x1="0" y1="7" x2="120" y2="7" stroke={color} strokeWidth="1" opacity=".5"/>
    <polygon points="130,7 136,3.5 142,7 136,10.5" fill={color} opacity=".8"/>
    <line x1="152" y1="7" x2="300" y2="7" stroke={color} strokeWidth="1" opacity=".5"/>
  </svg>
);

const STitle = ({ children, color }) => (
  <div style={{marginBottom:6,marginTop:2}}>
    <div style={{fontFamily:"var(--font-display)",fontSize:26,letterSpacing:"0.12em",color:color||"var(--gold)",marginBottom:5}}>{children}</div>
    <OrnLine color={color||"var(--gold-dim)"}/>
  </div>
);

const Chk = ({ checked, onChange, label }) => (
  <label style={{display:"flex",alignItems:"center",gap:7,cursor:"pointer",userSelect:"none",fontSize:14}}>
    <div onClick={onChange} style={{width:15,height:15,border:`1px solid ${checked?"var(--gold)":"var(--stone-border)"}`,borderRadius:3,background:checked?"var(--gold)":"transparent",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all .15s"}}>
      {checked&&<svg width="9" height="7" viewBox="0 0 9 7"><polyline points="1,3.5 3.5,6 8,1" stroke="var(--ink)" strokeWidth="1.5" fill="none"/></svg>}
    </div>
    {label}
  </label>
);

const DelBtn = ({ onClick }) => (
  <button onClick={onClick} style={{background:"none",border:"none",color:"var(--stone-border)",cursor:"pointer",fontSize:14,padding:"2px 4px",lineHeight:1,flexShrink:0,transition:"color .2s"}}
    onMouseEnter={e=>e.currentTarget.style.color="var(--crimson)"}
    onMouseLeave={e=>e.currentTarget.style.color="var(--stone-border)"}>✕</button>
);

const AddTag = ({ onAdd, ph }) => {
  const [v,setV]=useState("");
  return (
    <div style={{display:"flex",gap:6}}>
      <input value={v} onChange={e=>setV(e.target.value)} placeholder={ph} style={{flex:1,fontSize:13}}
        onKeyDown={e=>{if(e.key==="Enter"&&v.trim()){onAdd(v.trim());setV("");}}}/>
      <Btn size="sm" variant="ghost" onClick={()=>{if(v.trim()){onAdd(v.trim());setV("");}}}>+</Btn>
    </div>
  );
};

// ─── Анимированная раскрывашка ────────────────────────────────────────────────
// ─── Хук адаптива ────────────────────────────────────────────────────────────
const useIsMobile = () => {
  const [w, setW] = useState(window.innerWidth);
  useEffect(() => {
    const h = () => setW(window.innerWidth);
    window.addEventListener('resize', h);
    return () => window.removeEventListener('resize', h);
  }, []);
  return { isMobile: w < 640, isTablet: w < 900, width: w };
};

const ExpandPanel = ({ open, children }) => (
  <div style={{overflow:"hidden",transition:"max-height .4s cubic-bezier(0.4,0,0.2,1),opacity .25s ease",maxHeight:open?3000:0,opacity:open?1:0}}>
    {children}
  </div>
);

// ─── Карточка выбора (раса, класс, подкласс, предыстория) ────────────────────
const SelectCard = ({
  id, имя, icon, цвет="#c9a84c", bg="#1a1410",
  выбран, открыт, onSelect, onToggle,
  детали,
}) => {
  const выбранBorder = выбран ? цвет : "var(--stone-border)";
  const isPhoto = icon && icon.type === "img";
  const EASING = "cubic-bezier(0.4,0,0.2,1)";
  // Размеры миниатюры в шапке: схлопывается в 0 при открытии
  const thumbW = открыт && isPhoto ? 0 : 56;
  // Большое фото в раскрытом блоке: 160×160
  const BIG = 160;

  return (
    <div style={{borderRadius:8,overflow:"hidden",border:`1px solid ${выбранBorder}`,background:выбран?"rgba(0,0,0,0.5)":"var(--stone)",transition:`border-color .35s ${EASING}, box-shadow .35s`,boxShadow:выбран?`0 0 16px ${цвет}28`:открыт?"0 2px 12px rgba(0,0,0,0.4)":"none"}}>
      {/* Заголовок */}
      <div style={{display:"flex",alignItems:"center",cursor:"pointer",userSelect:"none",minHeight:56}}
        onClick={()=>{ onSelect(); onToggle(); }}>
        {/* Миниатюра — анимированно схлопывается при открытии */}
        <div style={{
          width:thumbW, height:56, flexShrink:0, overflow:"hidden",
          background:bg,
          transition:"border-color .2s",
        }}>
          {typeof icon === "string"
            ? <div style={{width:56,height:56,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,background:bg}}>{icon}</div>
            : icon}
        </div>
        {/* Название */}
        <div style={{flex:1,padding:"0 14px"}}>
          <div style={{fontFamily:"var(--font-title)",fontSize:14,letterSpacing:"0.06em",color:выбран?цвет:"var(--parchment)",transition:"color .2s"}}>{имя}</div>
          {выбран && <div style={{fontSize:11,color:цвет,opacity:.7,marginTop:1}}>✓ Выбрано</div>}
        </div>
        {/* Стрелка */}
        <div style={{padding:"0 14px",color:"var(--gold-dim)",fontSize:12,transition:`transform .35s ${EASING}`,transform:открыт?"rotate(180deg)":"rotate(0deg)"}}>▼</div>
      </div>

      {/* Раскрывающееся содержимое */}
      <ExpandPanel open={открыт}>
        <div style={{borderTop:`1px solid ${цвет}40`,background:`${bg}cc`}}>
          {isPhoto ? (
            <div style={{display:"flex",alignItems:"stretch",gap:0,flexWrap:"wrap"}}>
              {/* Фото */}
              <div style={{
                width:"min(160px,100%)", flexShrink:0, overflow:"hidden",
                minHeight:BIG,
              }}>
                {React.cloneElement(icon, {
                  style:{width:"100%",height:"100%",objectFit:"cover",display:"block",minHeight:BIG},
                })}
              </div>
              {/* Детали справа */}
              <div style={{flex:"1 1 200px",padding:"16px",minWidth:0,borderLeft:`1px solid ${цвет}30`}}>
                {детали}
              </div>
            </div>
          ) : (
            <div style={{padding:"14px 16px 14px 72px"}}>{детали}</div>
          )}
        </div>
      </ExpandPanel>
    </div>
  );
};

