// ─── Хук для управления единственной открытой карточкой ──────────────────────
function useAccordion() {
  const [открыт, setОткрыт] = useState(null);
  const toggle = useCallback((id) => setОткрыт(prev => prev === id ? null : id), []);
  return [открыт, toggle];
}

// ─── Шаг: Имя ─────────────────────────────────────────────────────────────────
const ШагИмя = ({ данные, onChange }) => (
  <div style={{maxWidth:480,margin:"0 auto"}}>
    <Panel>
      <STitle>Имя Героя</STitle>
      <div style={{marginBottom:18}}>
        <input value={данные.имя} onChange={e=>onChange({имя:e.target.value})} placeholder="Введите имя..." style={{fontSize:18,textAlign:"center",padding:"10px 16px"}}/>
      </div>
      <STitle>Пол персонажа</STitle>
      <div style={{display:"flex",gap:8,marginBottom:18}}>
        {[["М","Мужской"],["Ж","Женский"]].map(([val,лейбл])=>(
          <button key={val} onClick={()=>onChange({пол:val})} style={{
            flex:1, padding:"14px 8px", borderRadius:8, cursor:"pointer",
            fontFamily:"var(--font-title)", fontSize:13, letterSpacing:"0.06em",
            border:`2px solid ${данные.пол===val?"var(--gold)":"var(--stone-border)"}`,
            background:данные.пол===val?"rgba(201,168,76,0.15)":"var(--stone)",
            color:данные.пол===val?"var(--gold)":"var(--parchment)",
            transition:"all .2s",
            boxShadow:данные.пол===val?"0 0 12px rgba(201,168,76,0.2)":"none",
          }}>{лейбл}</button>
        ))}
      </div>
      <STitle>Уровень персонажа</STitle>
      <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
        {Array.from({length:20},(_,i)=>i+1).map(lvl=>(
          <button key={lvl} onClick={()=>onChange({уровень:lvl})} style={{
            width:40,height:40,borderRadius:4,
            border:`1px solid ${данные.уровень===lvl?"var(--gold)":"var(--stone-border)"}`,
            background:данные.уровень===lvl?"var(--gold)":"var(--stone)",
            color:данные.уровень===lvl?"var(--ink)":"var(--parchment)",
            fontFamily:"var(--font-title)",fontSize:14,cursor:"pointer",transition:"all .15s",
          }}>{lvl}</button>
        ))}
      </div>
    </Panel>
  </div>
);

